 1	import {
 2	  ResourceLink,
 3	  useK8sWatchResource,
 4	} from '@openshift-console/dynamic-plugin-sdk';
 5	import * as React from 'react';
 6	import { useTranslation } from 'react-i18next';
 7	import {
 8	  DescriptionListDescription,
 9	  DescriptionListGroup,
10	  DescriptionListTerm,
11	} from '@patternfly/react-core';
12	import { PersistentVolumeClaimModel, PipelineRunModel } from '../../models';
13	import { PersistentVolumeClaimKind } from '../../types';
14	import { getMatchedPVCs } from '../utils/pipeline-utils';
15	
16	export interface VolumeClaimTemplatesSectionProps {
17	  namespace: string;
18	  ownerResourceName: string;
19	  ownerResourceKind?: string;
20	}
21	
22	const VolumeClaimTemplatesSection: React.FC<
23	  VolumeClaimTemplatesSectionProps
24	> = ({
25	  namespace,
26	  ownerResourceName,
27	  ownerResourceKind = PipelineRunModel.kind,
28	}) => {
29	  const [pvcResources, loaded, loadError] = useK8sWatchResource<
30	    PersistentVolumeClaimKind[]
31	  >({
32	    kind: PersistentVolumeClaimModel.kind,
33	    isList: true,
34	    namespace,
35	  });
36	
37	  const { t } = useTranslation('plugin__pipelines-console-plugin');
38	
39	  if (!ownerResourceName || !loaded || loadError || pvcResources?.length === 0)
40	    return null;
41	
42	  const matchedPVCs = getMatchedPVCs(
43	    pvcResources,
44	    ownerResourceName,
45	    ownerResourceKind,
46	  );
47	
48	  if (!matchedPVCs || matchedPVCs.length === 0) return null;
49	
50	  return (
51	    <DescriptionListGroup data-test-id="volumeClaimTemplate-resources-section">
52	      <DescriptionListTerm>
53	        {t('VolumeClaimTemplate Resources')}
54	      </DescriptionListTerm>
55	      <DescriptionListDescription>
56	        {matchedPVCs.map((pvcResource) => {
57	          return (
58	            <ResourceLink
59	              name={pvcResource.metadata.name}
60	              key={pvcResource.metadata.name}
61	              namespace={pvcResource.metadata.namespace}
62	              kind={PersistentVolumeClaimModel.kind}
63	            />
64	          );
65	        })}
66	      </DescriptionListDescription>
67	    </DescriptionListGroup>
68	  );
69	};
70	
71	export default VolumeClaimTemplatesSection;

